function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const n = points.length;
    const yMap = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y)!.push(x);
    }

    let result = 0;

    // For each y-coordinate, process the x-values
    for (const [y, xs] of yMap.entries()) {
        const m = xs.length;
        if (m < 2) continue;

        // Count the number of pairs of points on the same y-coordinate
        const cnt = m * (m - 1) / 2;
        result = (result + cnt) % MOD;

        // For each pair of points on the same y-coordinate, look for other y-coordinates
        for (let i = 0; i < m; i++) {
            for (let j = i + 1; j < m; j++) {
                const x1 = xs[i];
                const x2 = xs[j];

                // Look for other y-coordinates that have points with x-values x1 or x2
                for (const [otherY, otherXs] of yMap.entries()) {
                    if (otherY === y) continue;

                    // Count how many points have x = x1 or x2
                    let count = 0;
                    for (const x of otherXs) {
                        if (x === x1 || x === x2) {
                            count++;
                        }
                    }

                    // Add the number of ways to form a trapezoid with this pair and the other points
                    result = (result + count) % MOD;
                }
            }
        }
    }

    return result;
}

